formulas.expression:
IF ( INCLUDES ({!Driving_Jobs_Work_Detail}, "LGV D Driver" ), "LGV D Driver, ",
      IF ( INCLUDES ({!Driving_Jobs_Work_Detail}, "LGV D1 Driver" ), "LGV D1 Driver, ", NULL)
      )

IF ( INCLUDES ({!Driving_Jobs_Work_Detail}, "LGV C+E Driver" ), "LGV C+E Driver, ", 
      IF ( INCLUDES ({!Driving_Jobs_Work_Detail}, "LGV C+E Driver (102 Restriction)" ), "LGV C+E Driver (102 Restriction), ", 
             IF ( INCLUDES ({!Driving_Jobs_Work_Detail}, "LGV C Driver" ), "LGV C Driver, ",
                   IF ( INCLUDES ({!Driving_Jobs_Work_Detail}, "LGV C1+E Driver" ), "LGV C1+E Driver, ",
                        IF ( INCLUDES ({!Driving_Jobs_Work_Detail}, "LGV C1 Driver" ), "LGV C1 Driver, ", NULL)
                   )
             )
       )
)
